class Solution {
public:
    int numberOfArrays(string s, int k) {
        int MOD = 1e9 + 7;
        int n = s.size();
        long long res = 1;
        for (int i = 0; i < n; i++) {
            long long cur = 0;
            for (int j = i; j < n; j++) {
                cur = cur * 10 + (s[j] - '0');
                if (cur > k) break;
                res = (res * (j - i + 1)) % MOD;
            }
        }
        return res;
    }
};
```
